#!/usr/bin/env python3
import os, sys, json, argparse, math, random
import numpy as np
from collections import deque

from cogniplan_env import ExplorationEnv


def euclidean(p1, p2):
    return math.hypot(p1[0] - p2[0], p1[1] - p2[1])


def build_graph(nodes):
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord = (n['coords'][0], n['coords'][1])
        coord_to_idx[coord] = i
    adj = [[] for _ in nodes]
    for i, n in enumerate(nodes):
        for nb_coord in n.get('neighbors', []):
            nb_key = (nb_coord[0], nb_coord[1])
            if nb_key in coord_to_idx:
                adj[i].append(coord_to_idx[nb_key])
    return coord_to_idx, adj


def bfs_shortest_path(start_coord, target_coord, coord_to_idx, adj, nodes):
    start_idx = coord_to_idx.get(start_coord)
    target_idx = coord_to_idx.get(target_coord)
    if start_idx is None or target_idx is None:
        return None
    if start_idx == target_idx:
        return []
    parent = [-1] * len(nodes)
    visited = [False] * len(nodes)
    q = deque([start_idx])
    visited[start_idx] = True
    while q:
        u = q.popleft()
        for v in adj[u]:
            if not visited[v]:
                visited[v] = True
                parent[v] = u
                if v == target_idx:
                    path = []
                    while v != start_idx:
                        path.append(v)
                        v = parent[v]
                    path.reverse()
                    return [nodes[i]['coords'] for i in path]
                q.append(v)
    return None


def closest_node_to(pos, nodes):
    min_d = float('inf')
    best = None
    for n in nodes:
        coord = (n['coords'][0], n['coords'][1])
        d = euclidean(pos, coord)
        if d < min_d:
            min_d = d
            best = coord
    return best


def frontier_centroid(frontiers):
    if not frontiers:
        return None
    avg_x = sum(f[0] for f in frontiers) / len(frontiers)
    avg_y = sum(f[1] for f in frontiers) / len(frontiers)
    return (avg_x, avg_y)


def smart_policy(obs, current_node_coord, coord_to_idx, adj, nodes, visited_recent, epsilon=0.05):
    """
    Returns target node coordinate to move to, or None if stuck.
    """
    neighbors = obs.get('neighbors', [])
    if not neighbors:
        return None
    neighbor_set = set(tuple(nb) for nb in neighbors)

    # epsilon-random for exploration (tie-breaking)
    if random.random() < epsilon:
        choices = [tuple(nb) for nb in neighbors]
        if choices:
            return random.choice(choices)
        return None

    # 1. immediate neighbor with highest utility, not recently visited
    best_util_neighbor = None
    best_util = -1
    for n in nodes:
        coord = (n['coords'][0], n['coords'][1])
        if coord in neighbor_set:
            if coord in visited_recent:
                continue
            util = n.get('utility', 0)
            if util > best_util:
                best_util = util
                best_util_neighbor = coord
    if best_util > 0:
        return best_util_neighbor

    # 2. global best utility node via BFS (ignore recently visited)
    target_coord = None
    max_util = -1
    for n in nodes:
        coord = (n['coords'][0], n['coords'][1])
        if coord in visited_recent:
            continue
        util = n.get('utility', 0)
        if util > max_util:
            max_util = util
            target_coord = coord
    if target_coord is not None and max_util > 0:
        path = bfs_shortest_path(current_node_coord, target_coord, coord_to_idx, adj, nodes)
        if path and len(path) > 0:
            next_node = path[0]
            if tuple(next_node) in neighbor_set:
                return tuple(next_node)

    # 3. navigate toward frontier centroid (closest node to centroid via BFS)
    frontiers = obs.get('frontiers', [])
    if frontiers:
        centroid = frontier_centroid(frontiers)
        nearest_node_to_centroid = closest_node_to(centroid, nodes)
        if nearest_node_to_centroid:
            path = bfs_shortest_path(current_node_coord, nearest_node_to_centroid, coord_to_idx, adj, nodes)
            if path and len(path) > 0:
                next_node = path[0]
                if tuple(next_node) in neighbor_set:
                    return tuple(next_node)

    # 4. fallback: nearest unvisited node (not recently visited)
    for n in nodes:
        coord = (n['coords'][0], n['coords'][1])
        if coord in neighbor_set and coord not in visited_recent:
            if not n.get('visited', False):
                return coord

    # 5. any neighbor not recently visited
    for nb in neighbors:
        if tuple(nb) not in visited_recent:
            return tuple(nb)

    # 6. last resort: any neighbor (even recently visited)
    if neighbors:
        return tuple(neighbors[0])
    return None


def run_episode(env, max_steps=128, epsilon=0.05):
    obs = env.reset()
    nodes = obs['nodes']
    robot_pos = obs['robot_pos']
    current_node = closest_node_to(robot_pos, nodes)
    if current_node is None:
        current_node = (nodes[0]['coords'][0], nodes[0]['coords'][1])
    coord_to_idx, adj = build_graph(nodes)
    visited_recent = deque(maxlen=3)

    for step in range(max_steps):
        target = smart_policy(obs, current_node, coord_to_idx, adj, nodes, visited_recent, epsilon)
        if target is None:
            break
        obs, info = env.step(target)
        # update current_node to target after movement (closest to new robot position)
        current_node = closest_node_to(obs['robot_pos'], nodes)
        if current_node is None:
            current_node = (nodes[0]['coords'][0], nodes[0]['coords'][1])
        visited_recent.append(current_node)
        if info.get('done', False):
            break

    metrics = env.get_metrics()
    return metrics


def evaluate_map(env, map_path, max_steps=128, epsilon=0.0):
    """Run deterministic episode on evaluation map."""
    obs = env.reset()
    nodes = obs['nodes']
    robot_pos = obs['robot_pos']
    current_node = closest_node_to(robot_pos, nodes)
    if current_node is None:
        current_node = (nodes[0]['coords'][0], nodes[0]['coords'][1])
    coord_to_idx, adj = build_graph(nodes)
    visited_recent = deque(maxlen=3)

    for step in range(max_steps):
        target = smart_policy(obs, current_node, coord_to_idx, adj, nodes, visited_recent, epsilon=0.0)
        if target is None:
            break
        obs, info = env.step(target)
        current_node = closest_node_to(obs['robot_pos'], nodes)
        if current_node is None:
            current_node = (nodes[0]['coords'][0], nodes[0]['coords'][1])
        visited_recent.append(current_node)
        if info.get('done', False):
            break

    return env.get_metrics()


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True, help='Path to evaluation directory')
    parser.add_argument('--checkpoint', required=True, help='Path to checkpoint directory (unused by heuristic, but required by contract)')
    parser.add_argument('--output', required=True, help='Path to output JSON file')
    args = parser.parse_args()

    eval_config_path = os.path.join(args.data_path, 'eval_config.json')
    if os.path.exists(eval_config_path):
        with open(eval_config_path, 'r') as f:
            eval_config = json.load(f)
    else:
        # assume default structure
        eval_config = {'n_maps_eval': 150}

    maps_dir = os.path.join(args.data_path, 'maps_eval')
    map_files = []
    for env_type in ['room', 'tunnel', 'outdoor']:
        type_dir = os.path.join(maps_dir, env_type)
        if os.path.isdir(type_dir):
            for fname in sorted(os.listdir(type_dir)):
                if fname.endswith('.png'):
                    map_files.append({
                        'path': os.path.join(type_dir, fname),
                        'env_type': env_type,
                        'map_name': f"{env_type}/{fname}"
                    })

    results = {
        'per_episode': [],
        'per_type': {},
        'total_episodes': len(map_files),
        'explored_rate': 0.0,
        'travel_distance': 0.0,
        'success_rate': 0.0
    }
    stats_by_type = {}
    for et in ['room', 'tunnel', 'outdoor']:
        stats_by_type[et] = {'explored_rate': 0.0, 'travel_distance': 0.0, 'success_rate': 0.0, 'count': 0, 'success_count': 0}

    total_success = 0
    total_explored = 0.0
    total_distance_succ = 0.0
    total_distance_all = 0.0

    for idx, m in enumerate(map_files):
        print(f"Evaluating {idx+1}/{len(map_files)}: {m['map_name']}", flush=True)
        env = ExplorationEnv(map_path=m['path'])
        metrics = evaluate_map(env, m['path'])
        success = int(metrics.get('success', False))
        explored_rate = metrics.get('explored_rate', 0.0)
        travel_distance = metrics.get('travel_distance', 0.0)

        ep_result = {
            'map_path': m['map_name'],
            'env_type': m['env_type'],
            'success': success,
            'travel_distance': travel_distance,
            'explored_rate': explored_rate
        }
        results['per_episode'].append(ep_result)

        total_success += success
        total_explored += explored_rate
        total_distance_all += travel_distance
        if success:
            total_distance_succ += travel_distance

        stats_by_type[m['env_type']]['count'] += 1
        stats_by_type[m['env_type']]['explored_rate'] += explored_rate
        stats_by_type[m['env_type']]['success_count'] += success
        if success:
            stats_by_type[m['env_type']]['travel_distance'] += travel_distance

    for et in ['room', 'tunnel', 'outdoor']:
        cnt = stats_by_type[et]['count']
        succ_cnt = stats_by_type[et]['success_count']
        results['per_type'][et] = {
            'explored_rate': stats_by_type[et]['explored_rate'] / cnt if cnt > 0 else 0.0,
            'travel_distance': stats_by_type[et]['travel_distance'] / succ_cnt if succ_cnt > 0 else 0.0,
            'success_rate': succ_cnt / cnt if cnt > 0 else 0.0
        }

    results['explored_rate'] = total_explored / len(map_files) if len(map_files) > 0 else 0.0
    results['success_rate'] = total_success / len(map_files) if len(map_files) > 0 else 0.0
    results['travel_distance'] = total_distance_succ / total_success if total_success > 0 else 0.0

    with open(args.output, 'w') as f:
        json.dump(results, f, indent=2)
    print(f"Results saved to {args.output}", flush=True)


if __name__ == '__main__':
    main()
